package basics;

import java.util.Scanner;

public class TypeConversion {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner sc = new Scanner(System.in);
		double d= sc.nextDouble();
		int result =(int)d;
		System.out.println(result);
		
		sc.close();
	}

}

